div.t-attf-style:
background: #{record.alert_severity.raw_value == 'critical' and 'linear-gradient(135deg, #ef4444 0%, #b91c1c 100%)' or (record.alert_severity.raw_value == 'warning' and 'linear-gradient(135deg, #f59e0b 0%, #b45309 100%)' or 'linear-gradient(135deg, #3b82f6 0%, #1d4ed8 100%)')};
color: white;
padding: 4px 12px;
border-radius: 50px;
box-shadow: 0 4px 12px #{record.alert_severity.raw_value == 'critical' and 'rgba(239, 68, 68, 0.4)' or (record.alert_severity.raw_value == 'warning' and 'rgba(245, 158, 11, 0.4)' or 'rgba(59, 130, 246, 0.4)')};
font-size: 10px;
font-weight: 800;
text-transform: uppercase;
letter-spacing: 1px;
display: flex;
align-items: center;
gap: 6px;
border: 1px solid rgba(255,255,255,0.2);
backdrop-filter: blur(4px);
